import lxml.etree as ET

def process_soap_request(xml_request: bytes, dtd_file: str = None) -> ET.Element:
    parser = ET.XMLParser(load_dtd=True, no_network=True)

    if dtd_file:
        try:
            dtd = ET.DTD(file=dtd_file)
            root = ET.fromstring(xml_request, parser)
            if not dtd.validate(root):
                raise ValueError(f"XML validation error: {dtd.error_log}")
        except ET.XMLSyntaxError as e:
            raise ValueError(f"XML parsing error: {e}")
        except ET.DTDParseError as e:
            raise ValueError(f"DTD parsing error: {e}")
    else:
        try:
            root = ET.fromstring(xml_request, parser)
        except ET.XMLSyntaxError as e:
            raise ValueError(f"XML parsing error: {e}")

    soap_ns = "http://schemas.xmlsoap.org/soap/envelope/"
    body_tag = f"{{{soap_ns}}}Body"

    body_element = root.find(body_tag)
    if body_element is None:
        raise ValueError("SOAP Body not found in the request.")

    # Return the first child of the Body element as the message body
    # or the Body element itself if it contains no children but has text content
    if len(body_element) > 0:
        return body_element[0]
    elif body_element.text and body_element.text.strip():
        return body_element
    else:
        raise ValueError("SOAP Body is empty or contains no valid message.")